def ckplayer_get_info_by_xml(ckinfo):
    """
    Parse CKPlayer info from an XML string into a dictionary.
    Returns a dict with keys: 'title', 'links', 'size', 'flashvars'
    """
    # Parse XML
    e = ET.XML(ckinfo)

    video_dict = {
        'title': '',
        'links': [],
        'size': 0,
        'flashvars': '',
    }

    # Safely access the dictified structure
    data = dictify(e).get('ckplayer', {})

    # Extract title if present
    info = data.get('info', [])
    if info:
        title_entries = info[0].get('title', []) if isinstance(info[0], dict) else []
        if title_entries:
            t = title_entries[0].get('_text') if isinstance(title_entries[0], dict) else None
            if t:
                video_dict['title'] = t.strip()

    # Compute size by summing sizes of all video entries, if available
    video_entries = data.get('video', [])
    if isinstance(video_entries, list) and video_entries:
        total_size = 0
        for v in video_entries:
            if not isinstance(v, dict):
                continue
            size_list = v.get('size', []) if isinstance(v.get('size', []), list) else []
            if size_list and isinstance(size_list[0], dict) and '_text' in size_list[0]:
                try:
                    total_size += int(size_list[0]['_text'])
                except (ValueError, TypeError):
                    pass
        video_dict['size'] = total_size

    # Collect links from each video entry if available
    if isinstance(video_entries, list) and video_entries:
        links = []
        for v in video_entries:
            if not isinstance(v, dict):
                continue
            file_list = v.get('file', []) if isinstance(v.get('file', []), list) else []
            if file_list and isinstance(file_list[0], dict) and '_text' in file_list[0]:
                link = file_list[0]['_text'].strip()
                if link:
                    links.append(link)
        if links:
            video_dict['links'] = links

    # Extract flashvars if present
    flashvars_list = data.get('flashvars', []) if isinstance(data.get('flashvars', []), list) else []
    if flashvars_list:
        fv_text = flashvars_list[0].get('_text') if isinstance(flashvars_list[0], dict) else None
        if fv_text:
            video_dict['flashvars'] = fv_text.strip()

    return video_dict
